TEST(BignumString, UInt512Overflow) {
    std::vector<std::string> values = {
        "134078079299425970995740249982058461274793658205923933777235614437217640300735469768018742"
        "98166903427690031858186486050853753882811946569946433649006084096",
        /* UINT_MAX + extra digit (one longer) */
        "134078079299425970995740249982058461274793658205923933777235614437217640300735469768018742"
        "981669034276900318581864860508537538828119465699464336490060840950",
        /* value far larger than the width */
        "999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999"
        "99999999999999999999999999999999999999999999999999999999999999999999999999",
    };

    for (auto& value : values) {
        CheckToStringOverflow<16>(value, SignMode::UNSIGNED);
    }
}

TEST(BignumString, Int512Overflow) {
    std::vector<std::string> values = {
        /* INT_MAX + 1 (= 2^511, exceeds positive range 2^511-1) */
        // NOLINTNEXTLINE(bugprone-suspicious-missing-comma)
        "6703903964971298549787012499102923063739682910296196688861780721860882015036773488400937149083451713845015929093243025426876941405"
        "973284973216824503042048",
        /* "+|INT_MIN|" => OVERFLOW (positive 2^511 out of range) */
        /* INT_MIN - 1 (negative, beyond -2^511) */
        "-670390396497129854978701249910292306373968291029619668886178072186088201503677348840093714908345171384501592909324302542687694140"
        "5973284973216824503042049",
        /* value far larger than the width, positive and negative */
        "9999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999"
        "9999999999999999999999999999999999",
        "-999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999"
        "99999999999999999999999999999999999",
        /* unsigned-max magnitude as signed => overflow (UINT_MAX >> INT_MAX, and >> |INT_MIN|) */
        "1340780792994259709957402499820584612747936582059239337772356144372176403007354697680187429816690342769003185818648605085375388281"
        "1946569946433649006084095",
        "-134078079299425970995740249982058461274793658205923933777235614437217640300735469768018742981669034276900318581864860508537538828"
        "11946569946433649006084095",
    };

    for (auto& value : values) {
        CheckToStringOverflow<16>(value, SignMode::SIGNED);
    }
}

TEST(BignumString, BadString) {
    std::vector<std::string> values{
        "",    "+",   "-",    "abc",  "12a3", "0x1f", "12.5", "1e9", "1_000", "1,000", "1/",  "1:", " 12",
        "12 ", "1 2", "\t12", "12\n", "12\r", "12\t", "--1",  "++1", "+-1",   "-+1",   "1-2", "1+", "\xd9\xa2",
    };
    for (auto& value : values) {
        CheckToStringBadString<4>(value, SignMode::UNSIGNED);
        CheckToStringBadString<8>(value, SignMode::UNSIGNED);
        CheckToStringBadString<16>(value, SignMode::UNSIGNED);
        CheckToStringBadString<4>(value, SignMode::SIGNED);
        CheckToStringBadString<8>(value, SignMode::SIGNED);
        CheckToStringBadString<16>(value, SignMode::SIGNED);
    }
}

TEST(BignumString, UnsignedBadString) {
    std::vector<std::string> values = {"-0", "-1", "-10"};
    for (auto& value : values) {
        CheckToStringBadString<4>(value, SignMode::UNSIGNED);
        CheckToStringBadString<8>(value, SignMode::UNSIGNED);
        CheckToStringBadString<16>(value, SignMode::UNSIGNED);
    }
}
